import{_ as e,o as t,c as i,a2 as o}from"./chunks/framework.B8zgMDLd.js";const d=JSON.parse('{"title":"Manage Git Manually Or With AutoGit","description":"","frontmatter":{},"headers":[],"relativePath":"guides/commit-and-push.md","filePath":"guides/commit-and-push.md"}'),l={name:"guides/commit-and-push.md"};function n(s,a,r,u,c,m){return t(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="manage-git-manually-or-with-autogit" tabindex="-1">Manage Git Manually Or With AutoGit <a class="header-anchor" href="#manage-git-manually-or-with-autogit" aria-label="Permalink to &quot;Manage Git Manually Or With AutoGit&quot;">​</a></h1><p>Tolaria can act as a lightweight Git client for a Git-enabled vault. You can manage commits and pushes yourself, or enable AutoGit to create conservative checkpoints after editing pauses or when the app is no longer active.</p><h2 id="manual-git" tabindex="-1">Manual Git <a class="header-anchor" href="#manual-git" aria-label="Permalink to &quot;Manual Git&quot;">​</a></h2><ol><li>Open the Git or changes surface.</li><li>Review changed files.</li><li>Write a short commit message.</li><li>Commit locally.</li><li>Push when a remote is configured.</li></ol><p>If the remote has changed, pull first and resolve any conflicts. If the vault has no remote, manual commits still give you local history, diffs, and rollback.</p><h2 id="autogit" tabindex="-1">AutoGit <a class="header-anchor" href="#autogit" aria-label="Permalink to &quot;AutoGit&quot;">​</a></h2><p>AutoGit is available in Settings for Git-enabled vaults. When enabled, Tolaria automatically commits and pushes saved local changes after an idle pause or after the app becomes inactive.</p><p>Use AutoGit when you want the safety of regular checkpoints without interrupting capture or editing. You can still inspect each note&#39;s current diff, review note history, and browse the whole-vault history before making larger manual commits.</p><h2 id="use-small-commits" tabindex="-1">Use Small Commits <a class="header-anchor" href="#use-small-commits" aria-label="Permalink to &quot;Use Small Commits&quot;">​</a></h2><p>Small commits make it easier to understand what changed, roll back safely, and review AI-generated edits.</p>',10)])])}const p=e(l,[["render",n]]);export{d as __pageData,p as default};
